  ('heelevel3-5ff21eeb-moex-00054', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關土地稅之納稅義務人何者錯誤？①土地設定典權者，典權人繳納土地增值稅  ②土地為', '["繼承而移轉之土地，取得所有權人為土 地增值稅納稅義務人", "他益信託下，受託人移轉信託土地與受益人，受益人為土地增值稅納稅 義務人", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00055', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列關於復查之規定何者錯誤？', '["依核定稅額通知書所載有應納稅額或應補徵稅額者，應於繳款書送達後，於繳納期間屆滿之翌 日起30日內，申請復查", "依核定稅額通知書所載無應納稅額或應補徵稅額者，應於核定稅額通知書送達之翌日起 30 日 內，申請復查", "稅捐稽徵機關對有關復查之申請，應於接到申請書之翌日起2個月內復查決定，並作成決定書， 通知納稅義務人", "納稅義務人或其代理人，因天災事變或其他不可抗力之事由，遲誤申請復查期間者，於其原因 消滅後2個月內，得提出具體證明，申請回復原狀，並應同時補行申請復查期間內應為之行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00056', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '政府對私有空地，得限期建築、增建、改建或重建，逾期加徵基本稅額幾倍之空地稅？', '["1~2倍", "2~3倍", "2~5倍", "3~6倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00057', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '中華民國國民取得香港馬票之中獎獎金20萬元應如何課稅？', '["納入年度個人綜合所得稅課稅", "納入年度個人綜合所得稅課稅，惟已向香港政府繳納中獎獎金之所得稅部分得扣抵之", "中獎人回國時向我國海關人員申報繳納所得稅", "免予繳納所得稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00058', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '同時申請自用住宅用地面積超過規定時，應自行擇定適用順序，若未擇定且地價稅額相同時，應', '["本人、配偶及未成年子女之戶籍所在地", "直系血親 尊親屬之戶籍所在地", "直系姻親之戶籍所在地", "直系血親卑親屬之戶籍所在地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00059', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-ad8fcc74', 'sub-heelevel3-5ff21eeb-04', NULL, 'essay', '甲向主管機關申請在某縣 A區開採礦物，甲提出申請後，審核終結前，
A 區被依法指定為保護區並公告禁止開採礦物，但機關承辦人乙不知 A
區已被指定為保護區並公告禁止開採礦物之事，仍核發開礦許可給甲，
甲收到許可後立即向外國廠商購買開礦所需之機械一批。稍後乙之主管
丙發現此事，立即再發函給甲撤銷原核發之開礦許可。問：依法令規定，
主管機關對於甲之申請究應予以核駁或核准？若甲對撤銷許可之處分
不服，提起救濟時得如何主張權利？（40分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "d09c279fbc55", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政作用及行政救濟相關法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00060', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-ad8fcc74', 'sub-heelevel3-5ff21eeb-04', NULL, 'essay', '若甲市政府辦理所屬各級學校營養午餐共同採購招標，計有 A、B 與 C
三家廠商參加投標，甲認定 C資格不符，問：C若不服，得如何尋求救
濟？若開標後，由 A餐飲企業得標，甲和 A簽訂行政契約，約定每餐支
付每位學生新臺幣五十元，A應提供一葷（豬雞輪替）二素菜且附湯並
提供水果。六個月後因物價與人工成本大漲，A向甲表示無法依約供應
餐點，欲終止契約，問：若甲願取消每餐之水果，堅持 A應繼續履行契
約，但 A不接受，A得如何主張其權益？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "d09c279fbc55", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政作用及行政救濟相關法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00061', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-ad8fcc74', 'sub-heelevel3-5ff21eeb-04', NULL, 'essay', '甲常年開車屢屢違反交通規則而遭主管機關多次裁罰，甲雖有財產卻從
不繳納相關罰鍰，總共積欠新臺幣（下同）十五萬元。主管機關於催告
無效後，即發函將甲之案件移送行政執行機關進行強制執行。行政執行
機關收案後發函催告甲，命其儘速完納，但甲置之不理。於是行政執行
機關查封甲所有之（價值一千萬元）房屋。問：執行機關之查封是否合
法？若甲不服，得如何救濟？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "d09c279fbc55", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政作用及行政救濟相關法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00062', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-4bf6d96a', 'sub-heelevel3-5ff21eeb-01', NULL, 'essay', '甲主張其所有之違章建築房屋被乙無權占用，乃本於所有權人之地位以
乙為被告，向管轄法院起訴請求判命乙應返還該屋給甲。由於乙主張其
係向甲購買該屋，雖未登記，但兩人有簽訂房屋買賣契約，並提出契約
為證。此外，乙更提起反訴請求確認系爭房屋之所有權屬於乙。
若甲於訴訟中承認確有和乙簽訂房屋買賣契約之事，但辯稱並未辦理
所有權移轉登記，故其仍為該屋之所有權人，問：法院對甲和乙提起
之訴應如何作出判決？（30分）
承前問題，若甲於乙提起反訴後，亦追加起訴請求確認該屋所有權屬
於甲，問：甲追加之訴是否合法？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "7134ad6ad7d6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1010", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00063', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-4bf6d96a', 'sub-heelevel3-5ff21eeb-01', NULL, 'essay', '甲（住基隆）從臺北市搭乘乙客運公司（總公司設於臺北市中山區）之
公車去新北市三重區上班，途經三重時因公車司機丙（住桃園市）闖紅
燈而和路過之大貨車發生擦撞，甲因而跌斷手臂。由於甲和乙、丙就賠
償金額未能達成協議，甲乃為原告並委任丁律師為全權訴訟代理人，以
乙和丙為共同被告，依侵權行為訴請臺灣新北地方法院判命乙與丙應連
帶賠償甲新臺幣（下同）一百萬元。問：
臺灣新北地方法院對本案件是否有管轄權？（20 分）
若於法院審理時，丁和乙、丙達成協議，二人願共同賠償甲五十萬元
而成立和解，並由書記官記明筆錄，該和解之效力如何？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "7134ad6ad7d6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1010", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
